public class Main {
    public static void main(String[] args) {

        int    quantity  = 4;
        double unitPrice = 1250.0;
        double gstRate   = 0.18;      // 18%

        // Basic arithmetic
        double subtotal  = unitPrice * quantity;
        double gstAmount = subtotal * gstRate;
        double total     = subtotal + gstAmount;

        System.out.printf("Unit Price : Rs %.2f%n", unitPrice);
        System.out.printf("Quantity   : %d%n",      quantity);
        System.out.printf("Subtotal   : Rs %.2f%n", subtotal);
        System.out.printf("GST (18%%) : Rs %.2f%n", gstAmount);
        System.out.printf("Total      : Rs %.2f%n", total);

        // Integer division and modulo demo
        int eggs   = 50;
        int dozens = eggs / 12;          // integer division
        int leftover = eggs % 12;        // remainder
        System.out.printf("%d eggs = %d dozen + %d left over%n",
                          eggs, dozens, leftover);

        // Math class
        double discount = Math.round(total * 0.05 * 100.0) / 100.0;
        System.out.printf("5%% discount: Rs %.2f%n", discount);
    }
}

